  ('real-estate-moex-02155', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於拋棄繼承之敘述，下列何者正確？', '["應於繼承開始之日起2個月內為之", "繼承之拋棄，溯及於繼承開始時發生效力", "拋棄繼承者，就其所管理之遺產，於拋棄當時不負任何責任", "配偶拋棄繼承權者，其應繼分應歸後順序之繼承人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02156', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲男乙女欲結婚，請問下列何種情形，甲乙不得結婚？', '["甲男曾與乙女之母親結婚，後因不孕而離婚", "甲18歲，乙17歲", "甲之祖母與乙之祖母為二親等之親姊妹", "甲之父母為丙、丁，乙之父母為戊、己，丙、己各自與前配偶離婚後，丙、己結婚"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 34, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02157', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於法定夫妻財產制，下列敘述，何者正確？', '["夫妻之一方以自己財產清償他方之債務時，於婚姻關係存續中，不得請求償還", "因繼承而得之財產，不計入夫或妻現存之婚後財產", "夫或妻於婚姻關係存續中，就其婚後財產所為履行道德上義務之贈與，他方得聲請法院撤銷之", "剩餘財產分配請求權專屬夫或妻享有，不得由繼承人主張之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
